SELECT * FROM (
    SELECT ID, SHOPCODE, SHOPNAME, SHOPBOSS, FUNDINGLIMIT, FUNDINGRATIO,
           ROW_NUMBER() OVER (ORDER BY ID DESC) AS RN
    FROM LZCUSTOMERINFOR

) WHERE RN > #{offset} AND RN <= #{offset} + #{pageSize}

SELECT ID, SHOPCODE, SHOPNAME, SHOPBOSS, FUNDINGLIMIT, FUNDINGRATIO
FROM LZCUSTOMERINFOR
WHERE ID = #{id}
